define("local_coursetags/coursetags",["core/ajax","core/templates"],(function(Ajax,Templates){
const SELECTORS={BOOST_UNION:'[data-region="course-content"][data-course-id]',STANDARD:".coursebox[data-courseid]"};
const getInjectionTarget=el=>{const c=el.querySelector(".course-info-container");if(c)return{element:c,position:"beforeend"};const n=el.querySelector(".aalink.coursename");if(n)return{element:n,position:"afterend"};const s=el.querySelector(".content .summary");if(s)return{element:s,position:"afterend"};return{element:el,position:"beforeend"}};
const init=async()=>{const m=new Map;document.querySelectorAll(SELECTORS.BOOST_UNION).forEach(el=>{const id=parseInt(el.dataset.courseId,10);if(id)m.set(id,el)});document.querySelectorAll(SELECTORS.STANDARD).forEach(el=>{const id=parseInt(el.dataset.courseid,10);if(id&&!m.has(id))m.set(id,el)});if(!m.size)return;const ids=[...m.keys()];let res;try{res=await Ajax.call([{methodname:"local_coursetags_get_course_tags",args:{courseids:ids}}])[0]}catch(e){window.console?.warn("local_coursetags: AJAX error",e);return}for(const d of res){if(!d.tags?.length)continue;const el=m.get(d.courseid);if(!el)continue;try{const{html}=await Templates.renderForPromise("local_coursetags/coursetags",{tags:d.tags});const{element:t,position:p}=getInjectionTarget(el);t.insertAdjacentHTML(p,html)}catch(e){window.console?.warn("local_coursetags: render error",d.courseid,e)}}};
return{init};
}));
